// ── Fuzzy Deduplication Engine ──────────────────────────────────
// Uses normalised string similarity on email domain + name + company
// Threshold: 85% similarity marks as DUPLICATE

const rows = $input.all().map((item, idx) => ({ ...item.json, _idx: idx }));
const THRESHOLD = 0.85;

// Levenshtein distance
function levenshtein(a, b) {
  if (!a || !b) return 1;
  a = a.toLowerCase().trim(); b = b.toLowerCase().trim();
  if (a === b) return 0;
  const m = a.length, n = b.length;
  const dp = Array.from({length: m + 1}, (_, i) => Array.from({length: n + 1}, (_, j) => i === 0 ? j : j === 0 ? i : 0));
  for (let i = 1; i <= m; i++) for (let j = 1; j <= n; j++) dp[i][j] = a[i-1] === b[j-1] ? dp[i-1][j-1] : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
  return dp[m][n];
}

function similarity(a, b) {
  if (!a && !b) return 1;
  if (!a || !b) return 0;
  const dist = levenshtein(String(a), String(b));
  const maxLen = Math.max(String(a).length, String(b).length);
  return maxLen === 0 ? 1 : 1 - (dist / maxLen);
}

function getEmailDomain(email) {
  return (email || '').split('@')[1]?.toLowerCase() || '';
}

const status = new Array(rows.length).fill('KEEP');
const audit_log = [];

for (let i = 0; i < rows.length; i++) {
  if (status[i] === 'DUPLICATE') continue;
  for (let j = i + 1; j < rows.length; j++) {
    if (status[j] === 'DUPLICATE') continue;
    const a = rows[i], b = rows[j];

    // Check 1: Exact email match
    const emailA = (a.email || a.Email || '').toLowerCase();
    const emailB = (b.email || b.Email || '').toLowerCase();
    if (emailA && emailB && emailA === emailB) {
      status[j] = 'DUPLICATE';
      audit_log.push({ kept_idx: i, removed_idx: j, reason: 'Exact email match', similarity: 1.0 });
      continue;
    }

    // Check 2: Same email domain + fuzzy name match
    const domainMatch = emailA && emailB && getEmailDomain(emailA) === getEmailDomain(emailB) && getEmailDomain(emailA) !== 'gmail.com';
    const nameSim = similarity(`${a.firstname || a.Firstname || ''} ${a.lastname || a.Lastname || ''}`, `${b.firstname || b.Firstname || ''} ${b.lastname || b.Lastname || ''}`);

    if (domainMatch && nameSim >= THRESHOLD) {
      status[j] = 'DUPLICATE';
      audit_log.push({ kept_idx: i, removed_idx: j, reason: `Domain match + name similarity ${(nameSim*100).toFixed(0)}%`, similarity: nameSim });
    }
  }
}

const clean_rows = rows.filter((_, i) => status[i] === 'KEEP');
const dup_rows = rows.filter((_, i) => status[i] === 'DUPLICATE');

return [{ json: {
  original_count: rows.length,
  clean_count: clean_rows.length,
  duplicate_count: dup_rows.length,
  clean_rows,
  audit_log
}}];

const data = $('Fuzzy Dedup Algorithm').first().json;
return data.clean_rows.map(row => {
  const { _idx, ...cleanRow } = row;
  return { json: cleanRow };
});

